mapper.delete:
DELETE FROM PRODUCT
WHERE PRODUCT_NO = #{productNo}
AND USER_NUM = #{userNum}

mapper.select:
SELECT * FROM ( SELECT PRODUCT_ROWS.*, ROWNUM AS RN FROM ( SELECT p.PRODUCT_NO, p.USER_NUM, p.CATEGORY_NO, p.PRODUCT_TITLE, p.PRODUCT_CONTENT, p.PRODUCT_CONDITION, p.PRICE, p.LOCATION, p.STATUS, p.ADMIN_HIDE_YN, p.HIDE_REASON, p.VIEW_COUNT, TO_CHAR(p.CREATE_DT, 'YYYY-MM-DD HH24:MI:SS') AS CREATE_DT_TEXT, TO_CHAR(p.MODIFY_DT, 'YYYY-MM-DD HH24:MI:SS') AS MODIFY_DT_TEXT, p.LIKE_CNT, p.CHAT_CNT, img.FILE_PATH AS THUMBNAIL_PATH, c1.CATEGORY_NAME AS LARGE_NAME, c2.CATEGORY_NAME AS MIDDLE_NAME, c3.CATEGORY_NAME AS SMALL_NAME FROM PRODUCT p
LEFT JOIN ( SELECT PRODUCT_NO, FILE_PATH FROM ( SELECT pi.PRODUCT_NO, pi.FILE_PATH, ROW_NUMBER() OVER ( PARTITION BY pi.PRODUCT_NO ORDER BY CASE WHEN pi.THUMBNAIL_YN = 'Y' THEN 0 ELSE 1 END, pi.IMAGE_ORDER, pi.IMAGE_NO ) AS IMAGE_RN FROM PRODUCT_IMAGE pi ) WHERE IMAGE_RN = 1 ) img ON p.PRODUCT_NO = img.PRODUCT_NO
) PRODUCT_ROWS WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}

mapper.update:
UPDATE PRODUCT
SET VIEW_COUNT = VIEW_COUNT + 1
WHERE PRODUCT_NO = #{productNo}

UPDATE PRODUCT
SET STATUS = #{status},
MODIFY_DT = SYSDATE
WHERE PRODUCT_NO = #{productNo}
AND USER_NUM = #{userNum}

UPDATE PRODUCT
SET CHAT_CNT = CHAT_CNT + 1
WHERE PRODUCT_NO = #{productNo}
